    // ==================== WS-Security Timestamp Handler ====================

    public static class WsSecurityTimestampHandler implements SOAPHandler<SOAPMessageContext> {

        private static final Logger HANDLER_LOGGER = Logger.getLogger(WsSecurityTimestampHandler.class.getName());
        private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
        private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
        private static final long TIMESTAMP_TOLERANCE_MS = 300_000; // 5 minutes
        private static final long REPLAY_CACHE_EXPIRY_MS = 600_000; // 10 minutes

        // Cache of message IDs/timestamps to detect replay attacks
        private static final ConcurrentMap<String, Long> replayCache = new ConcurrentHashMap<>();

        private static final SimpleDateFormat UTC_FORMAT = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
        static {
            UTC_FORMAT.setTimeZone(TimeZone.getTimeZone("UTC"));
        }

        @Override
        public Set<QName> getHeaders() {
            Set<QName> headers = new HashSet<>();
            headers.add(new QName(WSS_NS, "Security"));
            return headers;
        }

        @Override
        public boolean handleMessage(SOAPMessageContext context) {
            Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

            if (outbound != null && outbound) {
                return handleOutboundMessage(context);
            } else {
                return handleInboundMessage(context);
            }
        }

        private boolean handleOutboundMessage(SOAPMessageContext context) {
            try {
                SOAPMessage soapMessage = context.getMessage();
                SOAPEnvelope envelope = soapMessage.getSOAPPart().getEnvelope();
                SOAPHeader header = envelope.getHeader();

                if (header == null) {
                    header = envelope.addHeader();
                }

                // Add WS-Security header with Timestamp
                SOAPElement securityElement = header.addChildElement("Security", "wsse", WSS_NS);
                securityElement.addAttribute(envelope.createName("mustUnderstand", "soap",
                        envelope.getNamespaceURI()), "1");

                SOAPElement timestampElement = securityElement.addChildElement("Timestamp", "wsu", WSU_NS);
                String timestampId = "TS-" + UUID.randomUUID().toString();
                timestampElement.addAttribute(envelope.createName("Id", "wsu", WSU_NS), timestampId);

                Date now = new Date();
                Date expires = new Date(now.getTime() + TIMESTAMP_TOLERANCE_MS);

                SOAPElement createdElement = timestampElement.addChildElement("Created", "wsu", WSU_NS);
                synchronized (UTC_FORMAT) {
                    createdElement.addTextNode(UTC_FORMAT.format(now));
                }

                SOAPElement expiresElement = timestampElement.addChildElement("Expires", "wsu", WSU_NS);
                synchronized (UTC_FORMAT) {
                    expiresElement.addTextNode(UTC_FORMAT.format(expires));
                }

                soapMessage.saveChanges();
                HANDLER_LOGGER.info("Added WS-Security Timestamp to outbound message. ID: " + timestampId);

                return true;
            } catch (SOAPException e) {
                HANDLER_LOGGER.severe("Error adding WS-Security timestamp: " + e.getMessage());
                return false;
            }
        }

        private boolean handleInboundMessage(SOAPMessageContext context) {
            try {
                SOAPMessage soapMessage = context.getMessage();
                SOAPEnvelope envelope = soapMessage.getSOAPPart().getEnvelope();
                SOAPHeader header = envelope.getHeader();

                if (header == null) {
                    HANDLER_LOGGER.severe("SOAP Header is missing. WS-Security required.");
                    generateSOAPFault(context, "Missing SOAP Header. WS-Security header is required.");
                    return false;
                }

                // Extract WS-Security header
                Iterator<?> securityHeaders = header.getChildElements(new QName(WSS_NS, "Security"));
                if (!securityHeaders.hasNext()) {
                    HANDLER_LOGGER.severe("WS-Security header not found.");
                    generateSOAPFault(context, "WS-Security header is required.");
                    return false;
                }

                SOAPElement securityElement = (SOAPElement) securityHeaders.next();

                // Extract Timestamp
                Iterator<?> timestamps = securityElement.getChildElements(new QName(WSU_NS, "Timestamp"));
                if (!timestamps.hasNext()) {
                    HANDLER_LOGGER.severe("Timestamp element not found in WS-Security header.");
                    generateSOAPFault(context, "Timestamp is required in WS-Security header.");
                    return false;
                }

                SOAPElement timestampElement = (SOAPElement) timestamps.next();

                // Extract timestamp ID
                String timestampId = timestampElement.getAttributeNS(WSU_NS, "Id");
                if (timestampId == null || timestampId.isEmpty()) {
                    timestampId = "unknown-" + System.currentTimeMillis();
                }

                // Extract Created and Expires values
                String createdValue = extractChildText(timestampElement, WSU_NS, "Created");
                String expiresValue = extractChildText(timestampElement, WSU_NS, "Expires");

                HANDLER_LOGGER.info("Extracted Timestamp - ID: " + timestampId
                        + ", Created: " + createdValue + ", Expires: " + expiresValue);

                if (createdValue == null || createdValue.isEmpty()) {
                    HANDLER_LOGGER.severe("Created timestamp is missing.");
                    generateSOAPFault(context, "Created timestamp is required.");
                    return false;
                }

                // Parse timestamps
                Date createdDate = parseTimestamp(createdValue);
                Date expiresDate = (expiresValue != null && !expiresValue.isEmpty())
                        ? parseTimestamp(expiresValue) : null;

                if (createdDate == null) {
                    HANDLER_LOGGER.severe("Failed to parse Created timestamp: " + createdValue);
                    generateSOAPFault(context, "Invalid Created timestamp format.");
                    return false;
                }

                Date now = new Date();

                // Check if timestamp is in the future (with tolerance)
                if (createdDate.getTime() > now.getTime() + TIMESTAMP_TOLERANCE_MS) {
                    HANDLER_LOGGER.severe("Timestamp Created is in the future. Possible clock skew attack.");
                    generateSOAPFault(context, "Message timestamp is in the future.");
                    return false;
                }

                // Check if message has expired
                if (expiresDate != null && now.after(expiresDate)) {
                    HANDLER_LOGGER.severe("Message has expired. Expires: " + expiresValue);
                    generateSOAPFault(context, "Message has expired.");
                    return false;
                }

                // Check if message is too old (replay protection)
                long messageAge = now.getTime() - createdDate.getTime();
                if (messageAge > TIMESTAMP_TOLERANCE_MS) {
                    HANDLER_LOGGER.severe("Message timestamp is too old. Age: " + messageAge + "ms");
                    generateSOAPFault(context, "Message timestamp is too old. Possible replay attack.");
                    return false;
                }

                // Replay detection: check if we've seen this timestamp ID before
                String replayKey = timestampId + "|" + createdValue;
                Long previousTimestamp = replayCache.putIfAbsent(replayKey, now.getTime());
                if (previousTimestamp != null) {
                    HANDLER_LOGGER.severe("Replay attack detected! Duplicate timestamp ID: " + timestampId);
                    generateSOAPFault(context, "Replay attack detected. Duplicate message.");
                    return false;
                }

                // Clean up old entries from replay cache
                cleanupReplayCache();

                HANDLER_LOGGER.info("WS-Security Timestamp validation passed for ID: " + timestampId);

                // Store validated timestamp info in message context for service use
                context.put("ws.security.timestamp.created", createdDate);
                context.put("ws.security.timestamp.expires", expiresDate);
                context.put("ws.security.timestamp.id", timestampId);
                context.setScope("ws.security.timestamp.created", MessageContext.Scope.APPLICATION);
                context.setScope("ws.security.timestamp.expires", MessageContext.Scope.APPLICATION);
                context.setScope("ws.security.timestamp.id", MessageContext.Scope.APPLICATION);

                return true;

            } catch (SOAPException e) {
                HANDLER_LOGGER.severe("Error processing WS-Security header: " + e.getMessage());
                generateSOAPFault(context, "Error processing WS-Security header: " + e.getMessage());
                return false;
            }
        }

        private String extractChildText(SOAPElement parent, String namespace, String localName) {
            Iterator<?> children = parent.getChildElements(new QName(namespace, localName));
            if (children.hasNext()) {
                SOAPElement child = (SOAPElement) children.next();
                return child.getTextContent();
            }
            return null;
        }

        private Date parseTimestamp(String timestamp) {
            // Support multiple timestamp formats
            String[] formats = {
                    "yyyy-MM-dd'T'HH:mm:ss.SSS'Z'",
                    "yyyy-MM-dd'T'HH:mm:ss'Z'",
                    "yyyy-MM-dd'T'HH:mm:ss.SSSXXX",
                    "yyyy-MM-dd'T'HH:mm:ssXXX"
            };

            for (String format : formats) {
                try {
                    SimpleDateFormat sdf = new SimpleDateFormat(format);
                    sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
                    return sdf.parse(timestamp);
                } catch (Exception e) {
                    // Try next format
                }
            }
            return null;
        }

        private void cleanupReplayCache() {
            long now = System.currentTimeMillis();
            replayCache.entrySet().removeIf(entry ->
                    (now - entry.getValue()) > REPLAY_CACHE_EXPIRY_MS);
        }

        private void generateSOAPFault(SOAPMessageContext context, String faultMessage) {
            try {
                SOAPMessage soapMessage = context.getMessage();
                SOAPBody body = soapMessage.getSOAPPart().getEnvelope().getBody();
                body.removeContents();
                SOAPFault fault = body.addFault();
                fault.setFaultString(faultMessage);
                fault.setFaultCode(new QName(WSS_NS, "InvalidSecurity"));
                soapMessage.saveChanges();
            } catch (SOAPException e) {
                HANDLER_LOGGER.severe("Error generating SOAP fault: " + e.getMessage());
            }
        }

        @Override
        public boolean handleFault(SOAPMessageContext context) {
            HANDLER_LOGGER.warning("SOAP Fault occurred in WS-Security handler");
            logSOAPMessage(context);
            return true;
        }

        @Override
        public void close(MessageContext context) {
            // Cleanup if needed
        }

        private void logSOAPMessage(SOAPMessageContext context) {
            try {
                SOAPMessage message = context.getMessage();
                ByteArrayOutputStream baos = new ByteArrayOutputStream();
                message.writeTo(baos);
                HANDLER_LOGGER.fine("SOAP Message:\n" + baos.toString("UTF-8"));
            } catch (Exception e) {
                HANDLER_LOGGER.warning("Could not log SOAP message: " + e.getMessage());
            }
        }

        // Utility method to get replay cache size (for monitoring)
        public static int getReplayCacheSize() {
            return replayCache.size();
        }

        // Utility method to clear replay cache (for testing)
        public static void clearReplayCache() {
            replayCache.clear();
        }
    }

