    // ==================== SOAP Message Builder Utility ====================

    public static class SoapMessageBuilder {

        private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
        private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";

        public static SOAPMessage createPaymentRequestMessage(PaymentRequest request) throws SOAPException {
            MessageFactory messageFactory = MessageFactory.newInstance();
            SOAPMessage soapMessage = messageFactory.createMessage();
            SOAPPart soapPart = soapMessage.getSOAPPart();
            SOAPEnvelope envelope = soapPart.getEnvelope();

            envelope.addNamespaceDeclaration("pay", "http://payment.gateway.com/");
            envelope.addNamespaceDeclaration("wsse", WSS_NS);
            envelope.addNamespaceDeclaration("wsu", WSU_NS);

            // Build Security Header with Timestamp
            SOAPHeader header = envelope.getHeader();
            SOAPElement securityElement = header.addChildElement("Security", "wsse", WSS_NS);
            securityElement.addAttribute(envelope.createName("mustUnderstand", "soap",
                    envelope.getNamespaceURI()), "1");

            SOAPElement timestampElement = securityElement.addChildElement("Timestamp", "wsu", WSU_NS);
            String timestampId = "TS-" + UUID.randomUUID().toString();
            timestampElement.addAttribute(envelope.createName("Id", "wsu", WSU_NS), timestampId);

            SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
            sdf.setTimeZone(TimeZone.getTimeZone("UTC"));

            Date now = new Date();
            Date expires = new Date(now.getTime() + 300_000);

            SOAPElement createdElement = timestampElement.addChildElement("Created", "wsu", WSU_NS);
            createdElement.addTextNode(sdf.format(now));

            SOAPElement expiresElement = timestampElement.addChildElement("Expires", "wsu", WSU_NS);
            expiresElement.addTextNode(sdf.format(expires));

            // Build Body
            SOAPBody body = envelope.getBody();
            SOAPElement processPaymentElement = body.addChildElement("processPayment", "pay");
            SOAPElement paymentRequestElement = processPaymentElement.addChildElement("paymentRequest", "pay");

            addChildElement(paymentRequestElement, "transactionId", request.getTransactionId());
            addChildElement(paymentRequestElement, "amount", String.valueOf(request.getAmount()));
            addChildElement(paymentRequestElement, "currency", request.getCurrency());
            addChildElement(paymentRequestElement, "paymentMethod", request.getPaymentMethod());

            if (request.getCardNumber() != null) {
                addChildElement(paymentRequestElement, "cardNumber", request.getCardNumber());
            }
            if (request.getCardHolderName() != null) {
                addChildElement(paymentRequestElement, "cardHolderName", request.getCardHolderName());
            }
            if (request.getExpiryDate() != null) {
                addChildElement(paymentRequestElement, "expiryDate", request.getExpiryDate());
            }
            if (request.getMerchantId() != null) {
                addChildElement(paymentRequestElement, "merchantId", request.getMerchantId());
            }
            if (request.getDescription() != null) {
                addChildElement(paymentRequestElement, "description", request.getDescription());
            }
            if (request.getBankAccountNumber() != null) {
                addChildElement(paymentRequestElement, "bankAccountNumber", request.getBankAccountNumber());
            }
            if (request.getRoutingNumber() != null) {
                addChildElement(paymentRequestElement, "routingNumber", request.getRoutingNumber());
            }

            soapMessage.saveChanges();
            return soapMessage;
        }

        private static void addChildElement(SOAPElement parent, String name, String value) throws SOAPException {
            SOAPElement element = parent.addChildElement(name);
            element.addTextNode(value);
        }
    }

